"""Integration tests for repository scanner hardening."""

from __future__ import annotations

import subprocess

from agentheim.vendor.aictx.scan.scanner import scan_repository
from tests.fixtures.git_repos import create_git_repo


def _all_paths(inv) -> list[str]:
    return sorted(f.path for f in inv.files)


def _included_paths(inv) -> list[str]:
    return sorted(f.path for f in inv.files if not f.is_ignored)


def test_scan_excludes_aictx_runtime_artifacts() -> None:
    """Generated AICtx runtime files must never enter inventory."""
    repo = create_git_repo(
        {
            "README.md": "# Test",
            "src/main.py": "print('hello')",
            ".aictx/runs/fake-run/inventory.json": "{}",
            ".aictx/cache/cache.json": "{}",
            ".aictx/tmp/temp.txt": "tmp",
        }
    )
    inv = scan_repository(repo)
    included = _included_paths(inv)

    assert "README.md" in included
    assert "src/main.py" in included
    assert not any(p.startswith(".aictx/runs/") for p in included)
    assert not any(p.startswith(".aictx/cache/") for p in included)
    assert not any(p.startswith(".aictx/tmp/") for p in included)


def test_scan_prunes_hard_excluded_directories() -> None:
    """Ignored directories like node_modules must not be traversed."""
    repo = create_git_repo(
        {
            "README.md": "# Test",
            "src/main.py": "print('hello')",
            "node_modules/pkg/index.js": "module.exports = {}",
            "node_modules/pkg/package.json": "{}",
            "build/output.js": "// built",
        }
    )
    inv = scan_repository(repo)
    included = _included_paths(inv)

    assert "README.md" in included
    assert "src/main.py" in included
    assert not any(p.startswith("node_modules/") for p in included)
    assert not any(p.startswith("build/") for p in included)


def test_repeated_scan_file_paths_are_stable() -> None:
    """Two consecutive scans on the same repo must produce identical file lists."""
    repo = create_git_repo(
        {
            "README.md": "# Test",
            "src/aictx_sample.py": "print('hello')",
        }
    )
    inv1 = scan_repository(repo)
    inv2 = scan_repository(repo)

    assert _included_paths(inv1) == _included_paths(inv2)
    assert not any(p.startswith(".aictx/runs/") for p in _included_paths(inv1))
    assert not any(p.startswith(".aictx/runs/") for p in _included_paths(inv2))


def test_inventory_serializes_git_status() -> None:
    repo = create_git_repo(
        {
            "README.md": "# Test",
            "src/main.py": "print('hello')",
        }
    )
    inv = scan_repository(repo)

    assert inv.dirty_state is False
    assert inv.git_status.is_dirty is False
    assert "README.md" in inv.git_status.tracked_files
    assert "src/main.py" in inv.git_status.tracked_files
    dumped = inv.model_dump()
    assert "git_status" in dumped
    assert dumped["git_status"]["tracked_files"]


def test_scan_reports_untracked_modified_deleted_files() -> None:
    repo = create_git_repo(
        {
            "README.md": "# Test",
            "src/main.py": "print('hello')",
            "src/old.py": "print('old')",
        }
    )
    (repo / "src" / "main.py").write_text("print('changed')", encoding="utf-8")
    (repo / "notes.txt").write_text("untracked", encoding="utf-8")
    (repo / "src" / "old.py").unlink()
    subprocess.run(["git", "-C", str(repo), "add", "-u"], check=True, capture_output=True)

    inv = scan_repository(repo)

    assert inv.dirty_state is True
    assert inv.git_status.is_dirty is True
    assert "src/main.py" in inv.git_status.modified_files
    assert "notes.txt" in inv.git_status.untracked_files
    assert "src/old.py" in inv.git_status.deleted_files


def test_scan_marks_generated_context_artifacts() -> None:
    repo = create_git_repo(
        {
            "README.md": "# Test",
            "AGENTS.md": "# AGENTS.md\n\n> **Generated by:** `aictx`\n",
            "docs/AIprojectcontext/ai-index.md": "# AI Index\n",
            "src/main.py": "print('hello')",
        }
    )

    inv = scan_repository(repo)
    entries = {entry.path: entry for entry in inv.files}

    assert entries["AGENTS.md"].kind == "generated"
    assert entries["AGENTS.md"].is_generated is True
    assert entries["docs/AIprojectcontext/ai-index.md"].kind == "generated"
    assert entries["docs/AIprojectcontext/ai-index.md"].is_generated is True
    assert "docs/AIprojectcontext/ai-index.md" not in {entry.path for entry in inv.docs}
